.ue-wrap { position: relative; }
.ue-input { border: 0;
  border-bottom: 1px solid rgba(255,255,255,0.16);
  padding: 10px 2px 12px; outline: none; }
.ue-line { position: absolute; left: 0; right: 0; bottom: 0;
  height: 2px; background: #3b82f6;
  transform: scaleX(0); transform-origin: center;
  transition: transform 0.22s cubic-bezier(0.25,0.46,0.45,0.94); }
.ue-input:focus ~ .ue-line { transform: scaleX(1); }

// CSS only — JS 불필요
// 형제 선택자(~)로 input:focus 상태를 .ue-line에 전달
