.se-field.is-error .se-input { border-color: #ef4444;
  animation: se-shake 0.4s cubic-bezier(0.36,0.07,0.19,0.97) both; }
@keyframes se-shake {
  10%,90% { transform: translateX(-1px); }
  20%,80% { transform: translateX(2px); }
  30%,50%,70% { transform: translateX(-5px); }
  40%,60% { transform: translateX(5px); } }
.se-error { max-height: 0; opacity: 0; overflow: hidden;
  color: #f87171; transform: translateY(-4px);
  transition: max-height 0.22s ease-out, opacity 0.22s ease-out,
    transform 0.22s ease-out, margin-top 0.22s ease-out; }
.se-field.is-error .se-error {
  max-height: 40px; opacity: 1; transform: translateY(0); margin-top: 8px; }

var EMAIL = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
btn.addEventListener("click", function(){
  field.classList.remove("is-error");
  if (EMAIL.test(input.value.trim())) {
    input.setAttribute("aria-invalid", "false");
  } else {
    void field.offsetWidth; // reflow — 셰이크 애니메이션 재시작
    field.classList.add("is-error");
    input.setAttribute("aria-invalid", "true");
    input.focus();
  }
});

.cd-check { position: absolute; right: 13px; top: 50%;
  width: 20px; height: 20px;
  transform: translateY(-50%) scale(0.8); opacity: 0;
  transition: opacity 0.18s ease-out, transform 0.18s ease-out; }
.cd-check path { stroke-dasharray: 21; stroke-dashoffset: 21;
  transition: stroke-dashoffset 0.3s cubic-bezier(0.25,0.46,0.45,0.94) 0.05s; }
.cd-field.is-valid .cd-input { border-color: #22c55e; }
.cd-field.is-valid .cd-check { opacity: 1; transform: translateY(-50%) scale(1); }
.cd-field.is-valid .cd-check path { stroke-dashoffset: 0; }

