.pm-meter { display: flex; gap: 6px; margin-top: 12px; }
.pm-seg { flex: 1; height: 4px; border-radius: 2px;
  background: rgba(255,255,255,0.12);
  transition: background-color 0.24s ease-out,
    transform 0.24s cubic-bezier(0.34,1.56,0.64,1); }
.pm-meter[data-level="1"] .pm-seg:nth-child(1) { background: #ef4444; }
.pm-meter[data-level="2"] .pm-seg:nth-child(-n+2) { background: #f59e0b; }
.pm-meter[data-level="3"] .pm-seg:nth-child(-n+3) { background: #facc15; }
.pm-meter[data-level="4"] .pm-seg { background: #22c55e; }

function score(v){
  if (!v) return 0;
  var s = 0;
  if (v.length >= 8) s++;
  if (/[A-Z]/.test(v)) s++;
  if (/[0-9]/.test(v)) s++;
  if (/[^A-Za-z0-9]/.test(v)) s++;
  return Math.max(1, s);
}
input.addEventListener("input", function(){
  meter.setAttribute("data-level", String(score(input.value)));
});

.pr-toggle { position: absolute; right: 6px; top: 50%;
  transform: translateY(-50%);
  color: rgba(255,255,255,0.45);
  transition: color 0.18s ease-out; }
.pr-slash { stroke-dasharray: 22; stroke-dashoffset: 0;
  transition: stroke-dashoffset 0.24s cubic-bezier(0.25,0.46,0.45,0.94); }
.pr-toggle.is-visible { color: #3b82f6; }
.pr-toggle.is-visible .pr-slash { stroke-dashoffset: 22; }

toggle.addEventListener("click", function(){
  var visible = toggle.classList.toggle("is-visible");
  input.type = visible ? "text" : "password";
  toggle.setAttribute("aria-pressed", visible ? "true" : "false");
  toggle.setAttribute("aria-label",
    visible ? "비밀번호 숨기기" : "비밀번호 표시");
});

.otp-row { display: flex; gap: 8px; }
.otp-cell { width: 44px; height: 54px; text-align: center;
  font: 700 22px/1 sans-serif;
  border: 1px solid rgba(255,255,255,0.16); border-radius: 10px;
  transition: border-color 0.18s ease-out; }
.otp-cell:focus { border-color: #3b82f6; }
.otp-cell.is-filled { border-color: rgba(59,130,246,0.55);
  animation: otp-pop 0.22s cubic-bezier(0.34,1.56,0.64,1); }
@keyframes otp-pop {
  0% { transform: scale(0.9); }
  55% { transform: scale(1.07); }
  100% { transform: scale(1); } }

cells.forEach(function(cell, i){
  cell.addEventListener("input", function(){
    cell.value = cell.value.replace(/\D/g, "").slice(-1);
    cell.classList.toggle("is-filled", !!cell.value);
    if (cell.value && i < cells.length - 1) cells[i + 1].focus();
  });
  cell.addEventListener("keydown", function(e){
    if (e.key === "Backspace" && !cell.value && i > 0) {
      e.preventDefault();
      cells[i - 1].value = "";
      cells[i - 1].focus();
    }
  });
});

.cc-gauge { width: 16px; height: 16px; transform: rotate(-90deg); }
.cc-track { fill: none; stroke: rgba(255,255,255,0.12); stroke-width: 3; }
.cc-fill { fill: none; stroke: rgba(255,255,255,0.45);
  stroke-width: 3; stroke-linecap: round;
  stroke-dasharray: 50.27; /* 2 x PI x r(8) */
  stroke-dashoffset: 50.27;
  transition: stroke-dashoffset 0.18s ease-out, stroke 0.24s ease-out; }
.cc-meta[data-state="warn"] .cc-fill { stroke: #f59e0b; }
.cc-meta[data-state="max"] .cc-fill { stroke: #ef4444; }

var MAX = 80, CIRC = 50.27; // 2 x PI x r(8)
area.addEventListener("input", function(){
  var len = area.value.length;
  var ratio = Math.min(1, len / MAX);
  fill.style.strokeDashoffset = String(CIRC * (1 - ratio));
  count.textContent = len + " / " + MAX;
  meta.setAttribute("data-state",
    len >= MAX ? "max" : (ratio >= 0.7 ? "warn" : "idle"));
});

.sm-list { position: absolute; top: calc(100% + 6px);
  opacity: 0; transform: translateY(-6px) scale(0.98);
  pointer-events: none;
  transition: opacity 0.18s ease-out,
    transform 0.18s cubic-bezier(0.25,0.46,0.45,0.94); }
.sm-select.is-open .sm-list {
  opacity: 1; transform: translateY(0) scale(1); pointer-events: auto; }
.sm-select.is-open .sm-option {
  animation: sm-in 0.22s cubic-bezier(0.25,0.46,0.45,0.94) both; }
.sm-select.is-open .sm-option:nth-child(2) { animation-delay: 0.045s; }
.sm-select.is-open .sm-option:nth-child(3) { animation-delay: 0.09s; }
@keyframes sm-in {
  from { opacity: 0; transform: translateY(-6px); }
  to { opacity: 1; transform: translateY(0); } }
.sm-option.is-selected .sm-check { opacity: 1; transform: scale(1); }

trigger.addEventListener("click", function(){
  setOpen(!select.classList.contains("is-open"));
});
options.forEach(function(opt){
  opt.addEventListener("click", function(){
    options.forEach(function(o){ o.setAttribute("aria-selected", "false"); });
    opt.classList.add("is-selected");
    opt.setAttribute("aria-selected", "true");
    valueEl.textContent = opt.textContent.trim();
    setTimeout(function(){ setOpen(false); }, 220); // 체크 pop 노출 후 접힘
  });
});

.sb-btn { width: 100%; height: 52px; border-radius: 26px;
  overflow: hidden;
  transition: width 0.3s cubic-bezier(0.25,0.46,0.45,0.94),
    background 0.25s ease-out; }
.sb-btn[data-state="done"] { background: #22c55e; }
.sb-btn[data-state="loading"] .sb-label { opacity: 0; position: absolute; }
.sb-btn[data-state="loading"] .sb-spinner {
  opacity: 1; animation: sb-spin 0.7s linear infinite; }
@keyframes sb-spin { to { transform: rotate(360deg); } }
.sb-check path { stroke-dasharray: 21; stroke-dashoffset: 21; }
.sb-btn[data-state="done"] .sb-check path {
  animation: sb-draw 0.35s ease-out 0.15s forwards; }
@keyframes sb-draw { to { stroke-dashoffset: 0; } }

btn.addEventListener("click", function(){
  if (btn.getAttribute("data-state") !== "idle") return;
  var w = btn.offsetWidth;
  btn.style.width = w + "px";   // %는 px과 보간 불가 — 먼저 px 고정
  void btn.offsetWidth;         // reflow
  btn.setAttribute("data-state", "loading");
  btn.setAttribute("aria-busy", "true");
  btn.style.width = "52px";     // 높이와 같은 값 → 원형
